//#include <system_K1921__AUTO.h>        /* System initialization   			      */

/******************************************************************************/
/*                         System Specific Defenitions                        */
/******************************************************************************/
/*--  System memory ----------------------------------------------------------*/
/*--  Flash M size: 4M -------------------------------------------------------*/

#define MEM_FLASHM_BASE                      0x00000000UL
#define MEM_FLASHM_BUS_WIDTH_WORDS           4UL
#define MEM_FLASHM_PAGE_SIZE                 2048UL
#define MEM_FLASHM_PAGE_TOTAL                (8*512)UL
#define MEM_FLASHM_SIZE                      (MEM_MFLASH_PAGE_TOTAL*MEM_MFLASH_PAGE_SIZE)
/*--  Flash D size: 512kb ----------------------------------------------------*/
#define MEM_FLASHD_BASE                      0x00400000UL
#define MEM_FLASHD_BUS_WIDTH_WORDS           4UL
#define MEM_FLASHD_PAGE_SIZE                 2048UL
#define MEM_FLASHD_PAGE_TOTAL                (1*512)UL
#define MEM_FLASHD_SIZE                      (MEM_MFLASH_PAGE_TOTAL*MEM_MFLASH_PAGE_SIZE)

#define MEM_SDRAM_BASE                        0x80000000UL

#define LATENCY_DEFAULT                      (1)
#define LATENCY_100MHz                       (3)
#define LATENCY_150MHz                       (4)
#define LATENCY_200MHz                       (5)

/*--  RAM size: 512Kb --------------------------------------------------------*/
#define MEM_RAM_BASE                         0x20000000UL
#define MEM_RAM_SIZE                         0x4000UL

/*--  CFGWORD: System configure word -----------------------------------------*/
#define CFGWORD_BASE                          0x00001FF0UL

typedef struct {
    uint32_t JTAGEN               : 1;                              /*!< Enable JTAG pins (default 1 - enabled) */
    uint32_t CFGWE                : 1;                              /*!< CFG (NVR) flash region write enable (default 1 - enabled) */
    uint32_t FLASHWE              : 1;                              /*!< Main flash region write enable (default 1 - enabled) */
} CFGWORD_bits;

/* Bit field positions: */
#define CFGWORD_JTAGEN_Pos                    2                      /*!< Enable JTAG pins (default 1 - enabled) */
#define CFGWORD_CFGWE_Pos                     1                      /*!< CFG (NVR) flash region write enable (default 1 - enabled) */
#define CFGWORD_FLASHWE_Pos                   0                      /*!< Main flash region write enable (default 1 - enabled) */

/* Bit field masks: */
#define CFGWORD_JTAGEN_Msk                    0x00000004UL           /*!< Enable JTAG pins (default 1 - enabled) */
#define CFGWORD_CFGWE_Msk                     0x00000002UL           /*!< CFG (NVR) flash region write enable (default 1 - enabled) */
#define CFGWORD_FLASHWE_Msk                   0x00000001UL           /*!< Main flash region write enable (default 1 - enabled) */

/*--  Access codes to blocks -----------------------------------------*/
#define RCU_LOCK_CODE                         0xACCE55UL             /*!< Write this word to RCU LOCK register CODE field to with LOCK field lock/unlock access */
#define RCU_SYSRST_KEY                        0xA55AUL               /*!< Write this word to RCU RSTSYS register to KEY field with RSTEN field to perform software reset */

#define SIU_LOCK_CODE                         0xACCE55UL             /*!< Write this word to SIU LOCK register CODE field to with LOCK field lock/unlock access */
#define CORE1_ACCESS_CODE                     0xACCE55UL             /*!< Write this word to SIU CORE1_* registers CODE field to lock/unlock access */

#define FLASH_ACCESS_CODE                     0xC0DEUL               /*!< Write this word to FLASH CMD register to KEY field with specific command to perform flash access*/

#define GPIO_LOCK_CODE                        0xEEEEEEEEUL           /*!< Write this word to GPIO LOCKKEY register to lock */
#define GPIO_UNLOCK_CODE                      0xADEADBEEUL           /*!< Write this word to GPIO LOCKKEY register to unlock */

#define ADC_TEST_REG_ACCESS_CODE              0xFACCUL               /*!< Write this word to ADC ACTL[i].TACC0 KEY field to get register access */

/******************************************************************************/
/*                         DMA channel parameters                             */
/******************************************************************************/

/*--  BUFFER_SIZE: DMA channel Size of buffer (Not Block) to transfer --------------------------------*/
typedef struct {
    uint32_t BUFFSIZE             : 16;                              /*!< The operating mode of the DMA cycle */

} _CHANNEL_BUFFER_SIZE_bits;

/* Bit field positions: */
#define DMA_CHANNEL_BUFFER_SIZE_BUFFSIZE_Pos        0                /*!< The operating mode of the DMA cycle */

/* Bit field masks: */
#define DMA_CHANNEL_BUFFER_SIZE_BUFFSIZE_Msk        0x0000FFFFUL     /*!< The operating mode of the DMA cycle */

/*--  BLOCK_SIZE: DMA channel Size of buffer (Block) to transfer --------------------------------*/
typedef struct {
    uint32_t XSIZE             : 8;                               /*!< Block width */
    uint32_t YSIZE             : 8;                               /*!< Number of block lines */	
} _CHANNEL_BLOCK_SIZE_bits;

/* Bit field positions: */
#define DMA_CHANNEL_BLOCK_SIZE_XSIZE_Pos        0                 /*!< The operating mode of the DMA cycle */
#define DMA_CHANNEL_BLOCK_SIZE_YSIZE_Pos        8                 /*!< The operating mode of the DMA cycle */

/* Bit field masks: */
#define DMA_CHANNEL_BLOCK_SIZE_XSIZE_Msk        0x000000FFUL      /*!< The operating mode of the DMA cycle */
#define DMA_CHANNEL_BLOCK_SIZE_YSIZE_Msk        0x0000FF00UL      /*!< The operating mode of the DMA cycle */

