//--  ETHERNET_DMA_DESCR_TX_CTRL_STATUS: ETHERNET DMA transmit operations control and status word
typedef struct {
  uint32_t LENGTH                 :11;        /*!< The number of bytes to be transmitted */
  uint32_t ENABLE                 :1;         /*!< Set to one to enable the descriptor. Should always be set last of all the descriptor fields. */
  uint32_t WRAP                   :1;         /*!< Set to one to make the descriptor pointer wrap to zero after this descriptor has been used. If this bit is not set the pointer will increment by 8. The pointer automatically wraps to zero when the 1 kB boundary of the descriptor table is reached */
  uint32_t INTEN                  :1;         /*!< Enable Interrupts. An interrupt will be generated when the packet from this descriptor has been sent provided that the transmitter interrupt enable bit in the control register is set. The interrupt is generated regardless if the packet was transmitted successfully or if it terminated with an error. */
  uint32_t UNDERRUN_ERR           :1;         /*!< The packet was incorrectly transmitted due to a FIFO underrun error */
  uint32_t TRY_LIM_ERR            :1;         /*!< The packet was not transmitted because the maximum number of attempts (try) was reached */
  uint32_t LATE_COLL              :1;         /*!< A late collision occurred during the transmission (1000 Mbit mode only). */
  uint32_t MORE                   :1;         /*!< More descriptors should be fetched for this packet (Scatter Gather I/O) */
  uint32_t IP_CHECKSUM            :1;         /*!< Calculate and insert the IP header checksum for this packet. The checksum is only inserted if an IP packet is detected. */
  uint32_t TCP_CHECKSUM           :1;         /*!< Calculate and insert the TCP checksum for this packet. The checksum is only inserted if an TCP packet is detected */
  uint32_t UDP_CHECKSUM           :1;         /*!< Calculate and insert the UDP checksum for this packet. The checksum is only inserted if an UDP packet is detected*/
} _ETH_DMA_DESCR_TX_CTRL_STATUS_bits;

// Bit field positions:
