#define ETH_DMA_DESCR_TX_CTRL_STATUS_UDP_CHECKSUM_Msk         0x00100000UL

//--  ETH_DMA_DESCR_RX_CTRL_STATUS: ETH DMA receive operations control and status word
typedef struct {
  uint32_t LENGTH                 :11;         /*!< The number of bytes received to this descriptor */
  uint32_t ENABLE                 :1;          /*!< Set to one to enable the descriptor. Should always be set last of all the descriptor fields. */
  uint32_t WRAP                   :1;          /*!< Set to one to make the descriptor pointer wrap to zero after this descriptor has been used. If this bit is not set the pointer will increment by 8. The pointer automatically wraps to zero when the 1 kB boundary of the descriptor table is reached. */
  uint32_t INTEN                  :1;          /*!< Enable Interrupts. An interrupt will be generated when a packet has been received to this descriptor provided that the receiver interrupt enable bit in the control register is set. The interrupt is generated regardless if the packet was received successfully or if it terminated with an error. */
  uint32_t ALIGN_ERR              :1;          /*!< An odd number of nibbles were received */
  uint32_t FRAME_LONG             :1;          /*!< A frame larger than the maximum size was received. The excessive part was truncated. */
  uint32_t CRC_ERR                :1;          /*!< A CRC error was detected in this frame */
  uint32_t OVERRUN_ERR            :1;          /*!< The frame was incorrectly received due to a FIFO overrun */
  uint32_t LENGTH_ERR             :1;          /*!< The length/type field of the packet did not match the actual number of received bytes. */
  uint32_t IP_DETECT              :1;          /*!< IP packet detected */
  uint32_t IP_ERR                 :1;          /*!< IP checksum error detected */
  uint32_t UDP_DETECT             :1;          /*!< UDP packet detected */
  uint32_t UDP_ERR                :1;          /*!< UDP checksum error detected */
  uint32_t TCP_DETECT             :1;          /*!< TCP packet detected */
  uint32_t TCP_ERR                :1;          /*!< TCP checksum error detected */
  uint32_t IP_FRAGMENT            :1;          /*!< Fragmented IP packet detected */
  uint32_t MULTICAST_ADDR         :1;          /*!< The destination address of the packet was a multicast address (not broadcast) */
} _ETH_DMA_DESCR_RX_CTRL_STATUS_bits;

