#define MSC_IO_CTRL_UI_Pos                    28                     /*!< Upstream input Index */

/* Bit field masks: */
#define MSC_IO_CTRL_IC_Msk                    0x00000001UL           /*!< Invert Clock output */
#define MSC_IO_CTRL_IDTS_Msk                  0x00000002UL           /*!< Invert Data To Slave output */
#define MSC_IO_CTRL_ISS_Msk                   0x00000004UL           /*!< Invert Slave Select output */
#define MSC_IO_CTRL_IU_Msk                    0x00000008UL           /*!< Invert Upstream input */
